      55:    size_t newColumns = HeaderLayout_getColumns(hLayout);
      56: 
      57:    this->headerLayout = hLayout;
      58: 
      59:    if (newColumns == oldColumns)
      60:       return;
      61: 
      62:    if (newColumns > oldColumns) {
      63:       this->columns = xReallocArray(this->columns, newColumns, sizeof(Vector*));
