      68:       for (size_t i = newColumns; i < oldColumns; i++) {
      69:          for (int j = this->columns[i]->items - 1; j >= 0; j--) {
      70:             Vector_add(this->columns[newColumns - 1], Vector_take(this->columns[i], j));
      71:          }
      72:          Vector_delete(this->columns[i]);
      73:       }
      74:       this->columns = xReallocArray(this->columns, newColumns, sizeof(Vector*));
      75:    }
      76: 
      77:    Header_calculateHeight(this);
      78: }

