      97: static OpenFiles_ProcessData* OpenFilesScreen_getProcessData(pid_t pid) {
>>    98:    OpenFiles_ProcessData* pdata = xCalloc(1, sizeof(OpenFiles_ProcessData));
      99:    pdata->cols[getIndexForType('s')] = 8;
     100:    pdata->cols[getIndexForType('o')] = 8;
     101:    pdata->cols[getIndexForType('i')] = 8;
     102: 
     103:    int fdpair[2] = {-1, -1};
     104:    if (pipe(fdpair) < 0) {
     105:       pdata->error = 1;
     106:       return pdata;
     107:    }
     108: 
     109:    pid_t child = fork();
     110:    if (child < 0) {
     111:       close(fdpair[1]);
     112:       close(fdpair[0]);
     113:       pdata->error = 1;
     114:       return pdata;
     115:    }
     116: 
     117:    if (child == 0) {
     118:       close(fdpair[0]);
     119:       dup2(fdpair[1], STDOUT_FILENO);
     120:       close(fdpair[1]);
     121:       int fdnull = open("/dev/null", O_WRONLY);
     122:       if (fdnull < 0) {
     123:          exit(1);
     124:       }
     125: 
     126:       dup2(fdnull, STDERR_FILENO);
     127:       close(fdnull);
     128:       char buffer[32] = {0};
     129:       xSnprintf(buffer, sizeof(buffer), "%d", pid);
     130:       // Use of NULL in variadic functions must have a pointer cast.
     131:       // The NULL constant is not required by standard to have a pointer type.
     132:       execlp("lsof", "lsof", "-P", "-o", "-p", buffer, "-F", (char*)NULL);
     133:       exit(127);
     134:    }
     135:    close(fdpair[1]);
     136: 
     137:    OpenFiles_Data* item = &(pdata->data);
     138:    OpenFiles_FileData* fdata = NULL;
     139:    bool lsofIncludesFileSize = false;
     140: 
     141:    FILE* fp = fdopen(fdpair[0], "r");
     142:    if (!fp) {
     143:       pdata->error = 1;
     144:       return pdata;
     145:    }
     146:    for (;;) {
     147:       char* line = String_readLine(fp);
     148:       if (!line) {
     149:          break;
     150:       }
     151: 
     152:       unsigned char cmd = line[0];
     153:       switch (cmd) {
     154:          case 'f':  /* file descriptor */
     155:          {
     156:             OpenFiles_FileData* nextFile = xCalloc(1, sizeof(OpenFiles_FileData));
     157:             if (fdata == NULL) {
     158:                pdata->files = nextFile;
     159:             } else {
     160:                fdata->next = nextFile;
     161:             }
     162:             fdata = nextFile;
     163:             item = &(fdata->data);
     164:          } /* FALLTHRU */
     165:          case 'a':  /* file access mode */
     166:          case 'D':  /* file's major/minor device number */
     167:          case 'i':  /* file's inode number */
     168:          case 'n':  /* file name, comment, Internet address */
     169:          case 's':  /* file's size */
     170:          case 't':  /* file's type */
     171:          {
     172:             size_t index = getIndexForType(cmd);
     173:             free_and_xStrdup(&item->data[index], line + 1);
     174:             size_t dlen = strlen(item->data[index]);
     175:             if (dlen > (size_t)pdata->cols[index]) {
     176:                pdata->cols[index] = (int)CLAMP(dlen, 0, INT16_MAX);
     177:             }
     178:             break;
     179:          }
     180:          case 'o':  /* file's offset */
     181:          {
     182:             size_t index = getIndexForType(cmd);
     183:             if (String_startsWith(line + 1, "0t")) {
     184:                free_and_xStrdup(&item->data[index], line + 3);
     185:             } else {
     186:                free_and_xStrdup(&item->data[index], line + 1);
     187:             }
     188:             size_t dlen = strlen(item->data[index]);
     189:             if (dlen > (size_t)pdata->cols[index]) {
     190:                pdata->cols[index] = (int)CLAMP(dlen, 0, INT16_MAX);
     191:             }
     192:             break;
     193:          }
     194:          case 'c':  /* process command name  */
     195:          case 'd':  /* file's device character code */
     196:          case 'g':  /* process group ID */
     197:          case 'G':  /* file flags */
     198:          case 'k':  /* link count */
     199:          case 'l':  /* file's lock status */
     200:          case 'L':  /* process login name */
     201:          case 'p':  /* process ID */
     202:          case 'P':  /* protocol name */
     203:          case 'R':  /* parent process ID */
     204:          case 'T':  /* TCP/TPI information, identified by prefixes */
     205:          case 'u':  /* process user ID */
     206:             /* ignore */
     207:             break;
     208:       }
     209: 
     210:       if (cmd == 's')
     211:          lsofIncludesFileSize = true;
     212: 
     213:       free(line);
     214:    }
     215:    fclose(fp);
     216: 
     217:    int wstatus;
     218:    while (waitpid(child, &wstatus, 0) == -1)
     219:       if (errno != EINTR) {
     220:          pdata->error = 1;
     221:          return pdata;
     222:       }
     223: 
     224:    if (!WIFEXITED(wstatus)) {
     225:       pdata->error = 1;
     226:    } else {
     227:       pdata->error = WEXITSTATUS(wstatus);
     228:    }
     229: 
     230:    /* We got all information we need; no post-processing needed */
     231:    if (lsofIncludesFileSize)
     232:       return pdata;
     233: 
     234:    /* On linux, `lsof -o -F` omits SIZE, so add it back. */
     235:    /* On macOS, `lsof -o -F` includes SIZE, so this block isn't needed.  If no open files have a filesize, this will still run, unfortunately. */
     236:    size_t fileSizeIndex = getIndexForType('s');
     237:    for (fdata = pdata->files; fdata != NULL; fdata = fdata->next) {
     238:       item = &fdata->data;
     239:       const char* filename = getDataForType(item, 'n');
     240: 
     241:       struct stat sb;
     242:       if (stat(filename, &sb) == 0) {
     243:          char fileSizeBuf[21]; /* 20 (long long) + 1 (NULL) */
     244:          xSnprintf(fileSizeBuf, sizeof(fileSizeBuf), "%"PRIu64, (uint64_t)sb.st_size); /* sb.st_size is long long on macOS, long on linux */
     245:          free_and_xStrdup(&item->data[fileSizeIndex], fileSizeBuf);
     246:       }
     247:    }
     248: 
     249:    return pdata;
     250: }

     257: static void OpenFilesScreen_scan(InfoScreen* super) {
     258:    Panel* panel = super->display;
     259:    int idx = Panel_getSelectedIndex(panel);
     260:    Panel_prune(panel);
     261:    OpenFiles_ProcessData* pdata = OpenFilesScreen_getProcessData(((OpenFilesScreen*)super)->pid);
>>   262:    if (pdata->error == 127) {
