     266:    } else {
     267:       char hdrbuf[128] = {0};
     268:       snprintf(hdrbuf, sizeof(hdrbuf), "%5.5s %-7.7s %-4.4s %6.6s %*s %*s %*s  %s",
     269:          "FD", "TYPE", "MODE", "DEVICE",
