     271:          pdata->cols[getIndexForType('o')], "OFFSET",
     272:          pdata->cols[getIndexForType('i')], "NODE",
     273:          "NAME"
     274:       );
     275:       Panel_setHeader(panel, hdrbuf);
     276: 
     277:       OpenFiles_FileData* fdata = pdata->files;
     278:       while (fdata) {
     279:          OpenFiles_Data* data = &fdata->data;
     280:          char* entry = NULL;
     281:          xAsprintf(&entry, "%5.5s %-7.7s %-4.4s %6.6s %*s %*s %*s  %s",
     282:                    getDataForType(data, 'f'),
     283:                    getDataForType(data, 't'),
     284:                    getDataForType(data, 'a'),
     285:                    getDataForType(data, 'D'),
     286:                    pdata->cols[getIndexForType('s')],
     287:                    getDataForType(data, 's'),
     288:                    pdata->cols[getIndexForType('o')],
     289:                    getDataForType(data, 'o'),
     290:                    pdata->cols[getIndexForType('i')],
     291:                    getDataForType(data, 'i'),
     292:                    getDataForType(data, 'n'));
     293:          InfoScreen_addLine(super, entry);
     294:          free(entry);
     295:          OpenFiles_Data_clear(data);
     296:          OpenFiles_FileData* old = fdata;
     297:          fdata = fdata->next;
     298:          free(old);
     299:       }
     300:       OpenFiles_Data_clear(&pdata->data);
     301:    }
     302:    free(pdata);
     303:    Vector_insertionSort(super->lines);
