     468: HandlerResult Panel_selectByTyping(Panel* this, int ch) {
     469:    int size = Panel_size(this);
     470: 
     471:    if (ch == '#')
     472:       return IGNORED;
     473: 
     474:    if (!this->eventHandlerState)
>>   475:       this->eventHandlerState = xCalloc(100, sizeof(char));
     476: 
     477:    char* buffer = this->eventHandlerState;
     478: 
     479:    if (0 < ch && ch < 255 && isgraph((unsigned char)ch)) {
     480:       size_t len = strlen(buffer);
     481:       if (!len) {
     482:          if ('/' == ch) {
     483:             ch = '\001';
     484:          } else if ('q' == ch) {
     485:             return BREAK_LOOP;
     486:          }
     487:       } else if (1 == len && '\001' == buffer[0]) {
     488:          len--;
     489:       }
     490: 
     491:       if (len < 99) {
     492:          buffer[len] = (char) ch;
     493:          buffer[len + 1] = '\0';
     494:       }
     495: 
     496:       for (int try = 0; try < 2; try++) {
     497:          len = strlen(buffer);
     498:          for (int i = 0; i < size; i++) {
     499:             const char* cur = ((ListItem*) Panel_get(this, i))->value;
     500:             while (*cur == ' ')
     501:                cur++;
     502:             if (strncasecmp(cur, buffer, len) == 0) {
     503:                Panel_setSelected(this, i);
     504:                return HANDLED;
     505:             }
     506:          }
     507: 
     508:          // if current word did not match,
     509:          // retry considering the character the start of a new word.
     510:          buffer[0] = (char) ch;
     511:          buffer[1] = '\0';
     512:       }
     513: 
     514:       return HANDLED;
     515:    } else if (ch != ERR) {
     516:       buffer[0] = '\0';
     517:    }
     518: 
     519:    if (ch == 13) {
     520:       return BREAK_LOOP;
     521:    }
     522: 
     523:    return IGNORED;
     524: }

