     230: static void ScreenSettings_readFields(ScreenSettings* ss, Hashtable* columns, const char* line) {
     231:    char* trim = String_trim(line);
     232:    char** ids = String_split(trim, ' ', NULL);
     233:    free(trim);
     234: 
     235:    /* reset default fields */
     236:    memset(ss->fields, '\0', LAST_PROCESSFIELD * sizeof(ProcessField));
     237: 
     238:    for (size_t j = 0, i = 0; ids[i]; i++) {
     239:       if (j >= UINT_MAX / sizeof(ProcessField))
     240:          continue;
     241:       if (j >= LAST_PROCESSFIELD) {
>>   242:          ss->fields = xRealloc(ss->fields, (j + 1) * sizeof(ProcessField));
     243:          memset(&ss->fields[j], 0, sizeof(ProcessField));
     244:       }
     245:       int id = toFieldIndex(columns, ids[i]);
     246:       if (id >= 0)
     247:          ss->fields[j++] = id;
     248:       if (id > 0 && id < LAST_PROCESSFIELD)
     249:          ss->flags |= Process_fields[id].flags;
     250:    }
     251:    String_freeArray(ids);
     252: }

