     745: static void LinuxProcessTable_readMaps(LinuxProcess* process, openat_arg_t procFd, const LinuxMachine* host, bool calcSize, bool checkDeletedLib) {
     746:    Process* proc = (Process*)process;
     747: 
     748:    proc->usesDeletedLib = false;
     749: 
     750:    FILE* mapsfile = fopenat(procFd, "maps", "r");
     751:    if (!mapsfile)
     752:       return;
     753: 
     754:    Hashtable* ht = NULL;
     755:    if (calcSize)
>>   756:       ht = Hashtable_new(64, true);
     757: 
     758:    char buffer[1024];
     759:    while (fgets(buffer, sizeof(buffer), mapsfile)) {
     760:       uint64_t map_start;
     761:       uint64_t map_end;
     762:       bool map_execute;
     763:       uint64_t map_devmaj;
     764:       uint64_t map_devmin;
     765:       uint64_t map_inode;
     766: 
     767:       // Short circuit test: Look for a slash
     768:       if (!strchr(buffer, '/'))
     769:          continue;
     770: 
     771:       // Parse format: "%Lx-%Lx %4s %x %2x:%2x %Ld"
     772:       char* readptr = buffer;
     773: 
     774:       map_start = fast_strtoull_hex(&readptr, 16);
     775:       if ('-' != *readptr++)
     776:          continue;
     777: 
     778:       map_end = fast_strtoull_hex(&readptr, 16);
     779:       if (' ' != *readptr++)
     780:          continue;
     781: 
     782:       if (!readptr[0] || !readptr[1] || !readptr[2] || !readptr[3])
     783:          continue;
     784: 
     785:       map_execute = (readptr[2] == 'x');
     786:       readptr += 4;
     787:       if (' ' != *readptr++)
     788:          continue;
     789: 
     790:       while (*readptr > ' ')
     791:          readptr++; // Skip parsing this hex value
     792:       if (' ' != *readptr++)
     793:          continue;
     794: 
     795:       map_devmaj = fast_strtoull_hex(&readptr, 4);
     796:       if (':' != *readptr++)
     797:          continue;
     798: 
     799:       map_devmin = fast_strtoull_hex(&readptr, 4);
     800:       if (' ' != *readptr++)
     801:          continue;
     802: 
     803:       //Minor shortcut: Once we know there's no file for this region, we skip
     804:       if (!map_devmaj && !map_devmin)
     805:          continue;
     806: 
     807:       map_inode = fast_strtoull_dec(&readptr, 0);
     808:       if (!map_inode)
     809:          continue;
     810: 
     811:       if (calcSize) {
     812:          LibraryData* libdata = Hashtable_get(ht, (ht_key_t)map_inode);
     813:          if (!libdata) {
     814:             libdata = xCalloc(1, sizeof(LibraryData));
     815:             Hashtable_put(ht, (ht_key_t)map_inode, libdata);
     816:          }
     817: 
     818:          libdata->size += map_end - map_start;
     819:          libdata->exec |= map_execute;
     820:       }
     821: 
     822:       if (checkDeletedLib && map_execute && !proc->usesDeletedLib) {
     823:          while (*readptr == ' ')
     824:             readptr++;
     825: 
     826:          if (*readptr != '/')
     827:             continue;
     828: 
     829:          if (String_startsWith(readptr, "/memfd:"))
     830:             continue;
     831: 
     832:          /* Virtualbox maps /dev/zero for memory allocation. That results in
     833:           * false positive, so ignore. */
     834:          if (String_eq(readptr, "/dev/zero (deleted)\n"))
     835:             continue;
     836: 
     837:          if (strstr(readptr, " (deleted)\n")) {
     838:             proc->usesDeletedLib = true;
     839:             if (!calcSize)
     840:                break;
     841:          }
     842:       }
     843:    }
     844: 
     845:    fclose(mapsfile);
     846: 
>>   847:    if (calcSize) {
