    1306:    // Limit to MAX_CMDLINE_BUFFER_SIZE to prevent excessive memory allocation
    1307:    while (*amtRead > 0 && (size_t)*amtRead == bufferSize - 1 && bufferSize < MAX_CMDLINE_BUFFER_SIZE) {
    1308:       bufferSize *= 2;
>>  1309:       buffer = xRealloc(buffer, bufferSize);
    1310:       *amtRead = Compat_readfileat(procFd, filename, buffer, bufferSize);
    1311:    }
    1312: 
>>  1313:    if (*amtRead <= 0) {
    1314:       free(buffer);
    1315:       return NULL;
    1316:    }
    1317: 
    1318:    return buffer;
    1319: }

