     845: static void Platform_Battery_getSysData(double* percent, ACPresence* isOnAC) {
     846:    *percent = NAN;
     847:    *isOnAC = AC_ERROR;
     848: 
     849:    DIR* dir = opendir(SYS_POWERSUPPLY_DIR);
     850:    if (!dir)
     851:       return;
     852: 
     853:    uint64_t totalFull = 0;
     854:    uint64_t totalRemain = 0;
     855: 
     856:    const struct dirent* dirEntry;
>>   857:    while ((dirEntry = readdir(dir))) {
     858:       const char* entryName = dirEntry->d_name;
     859: 
     860: #ifdef HAVE_OPENAT
     861:       int entryFd = openat(xDirfd(dir), entryName, O_DIRECTORY | O_PATH);
     862:       if (entryFd < 0)
     863:          continue;
     864: #else
     865:       char entryFd[4096];
     866:       xSnprintf(entryFd, sizeof(entryFd), SYS_POWERSUPPLY_DIR "/%s", entryName);
     867: #endif
     868: 
     869:       enum { AC, BAT } type;
     870:       if (String_startsWith(entryName, "BAT")) {
     871:          type = BAT;
     872:       } else if (String_startsWith(entryName, "AC")) {
     873:          type = AC;
     874:       } else {
     875:          char buffer[32];
     876:          ssize_t ret = Compat_readfileat(entryFd, "type", buffer, sizeof(buffer));
     877:          if (ret <= 0)
     878:             goto next;
     879: 
     880:          /* drop optional trailing newlines */
     881:          for (char* buf = &buffer[(size_t)ret - 1]; *buf == '\n'; buf--)
     882:             *buf = '\0';
     883: 
     884:          if (String_eq(buffer, "Battery"))
     885:             type = BAT;
     886:          else if (String_eq(buffer, "Mains"))
     887:             type = AC;
     888:          else
     889:             goto next;
     890:       }
     891: 
     892:       if (type == BAT) {
     893:          char buffer[1024];
     894:          ssize_t r = Compat_readfileat(entryFd, "uevent", buffer, sizeof(buffer));
     895:          if (r < 0)
     896:             goto next;
     897: 
     898:          bool full = false;
     899:          bool now = false;
     900: 
     901:          double fullCharge = 0;
     902:          double capacityLevel = NAN;
     903:          const char* line;
     904: 
     905:          char* buf = buffer;
     906:          while ((line = strsep(&buf, "\n")) != NULL) {
     907:             char field[100] = {0};
     908:             int val = 0;
     909:             if (2 != sscanf(line, "POWER_SUPPLY_%99[^=]=%d", field, &val))
     910:                continue;
     911: 
     912:             if (String_eq(field, "CAPACITY")) {
     913:                capacityLevel = val / 100.0;
     914:                continue;
     915:             }
     916: 
     917:             if (String_eq(field, "ENERGY_FULL") || String_eq(field, "CHARGE_FULL")) {
     918:                fullCharge = val;
     919:                totalFull += fullCharge;
     920:                full = true;
     921:                if (now)
     922:                   break;
     923:                continue;
     924:             }
     925: 
     926:             if (String_eq(field, "ENERGY_NOW") || String_eq(field, "CHARGE_NOW")) {
     927:                totalRemain += val;
     928:                now = true;
     929:                if (full)
     930:                   break;
     931:                continue;
     932:             }
     933:          }
     934: 
     935:          if (!now && full && isNonnegative(capacityLevel))
     936:             totalRemain += capacityLevel * fullCharge;
     937: 
     938:       } else if (type == AC) {
     939:          if (*isOnAC != AC_ERROR)
     940:             goto next;
     941: 
     942:          char buffer[2];
     943:          ssize_t r = Compat_readfileat(entryFd, "online", buffer, sizeof(buffer));
     944:          if (r < 1) {
     945:             *isOnAC = AC_ERROR;
     946:             goto next;
     947:          }
     948: 
     949:          if (buffer[0] == '0')
     950:             *isOnAC = AC_ABSENT;
     951:          else if (buffer[0] == '1')
     952:             *isOnAC = AC_PRESENT;
     953:       }
     954: 
     955: next:
     956:       Compat_openatArgClose(entryFd);
     957:    }
     958: 
     959:    closedir(dir);
     960: 
     961:    *percent = totalFull > 0 ? ((double) totalRemain * 100.0) / (double) totalFull : NAN;
     962: }

